using System;
using System.Linq;
using Tgirrr.CadLisp;
class Tests {static int passed;static void Check(string n,bool ok){if(!ok)throw new Exception("FAILED: "+n);Console.WriteLine("PASS: "+n);passed++;}static SequenceSettings S(string text,int part=0,int step=1){return new SequenceSettings{Part=CopySequenceService.Parts(text)[part],Kind=CopySequenceService.Parts(text)[part].Numeric?SequenceKind.Number:SequenceKind.Letters,Step=step};}static void Main(){Check("attribute zero padding",CopySequenceService.Apply("VAN-009",S("VAN-009",1),1)=="VAN-010");Check("dimension override",CopySequenceService.Apply("ZONE-01 <>",S("ZONE-01 <>",1),1)=="ZONE-02 <>");Check("mleader text",CopySequenceService.Apply("ML-A",S("ML-A",1),1)=="ML-B");Check("table-like cell",CopySequenceService.Apply("A-01",S("A-01",1),3)=="A-04");Check("step",CopySequenceService.Apply("P10",S("P10",1,5),2)=="P20");var custom=S("X1",1);custom.Kind=SequenceKind.Custom;custom.Values=new[]{"ĐỎ","XANH"};custom.End=CustomEnd.Cycle;Check("custom cycle",CopySequenceService.Apply("X1",custom,3)=="XĐỎ");Check("parts discovered",CopySequenceService.Parts("A12-B03").Count==4);Console.WriteLine($"CPLUS regression: {passed} tests passed.");}}
